$wpdb->get_results(
			"
			SELECT ID AS 'value', post_title AS label, post_type AS 'type'
			FROM {$wpdb->posts}
			{$wpml_query}
			WHERE
				post_type IN ( {$post_types} ) AND post_status = 'publish' {$query}
			ORDER BY {$ordered_by}
			LIMIT 20
		",
			ARRAY_A
		)

